<script lang="ts">
  import { resolve } from '$app/paths';
  import { page } from '$app/stores';

  import { i18n } from '$lib/i18n';

  import { 
    PAGE_COMPONENT_MAP, 
    TOOL_COMPONENT_MAP, 
    getPageBySlug, 
    getToolBySlug 
  } from '$lib/registry';
  import { recentStore } from '$lib/stores/recent.svelte';

  // Lấy slug từ URL (Đổi tên biến cho chuẩn ngữ nghĩa)
  let currentSlug = $derived($page.params.slug ?? '/');

  // 1. Tìm Data bằng SLUG
  let toolInfo = $derived(getToolBySlug(currentSlug));
  let pageInfo = $derived(getPageBySlug(currentSlug));

  // 2. Tìm Component bằng ID nội bộ (Chỉ tìm khi toolInfo/pageInfo tồn tại)
  let ActiveToolComponent = $derived(toolInfo ? TOOL_COMPONENT_MAP[toolInfo.id] : null);
  let ActivePageComponent = $derived(pageInfo ? PAGE_COMPONENT_MAP[pageInfo.id] : null);

  $effect(() => {
    if (toolInfo) {
      recentStore.add(toolInfo.id);
    }
  });
</script>

<div class="w-full">
  {#if toolInfo && ActiveToolComponent}
    <ActiveToolComponent tool={toolInfo} />

  {:else if pageInfo && ActivePageComponent}
    <ActivePageComponent />

  {:else}
    <div class="p-12 text-center bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-2xl shadow-sm">
      <h2 class="text-lg font-semibold text-red-500">{i18n.t('error.pageNotFound')}</h2>
      <p class="text-sm text-gray-400 mt-1">{i18n.t('error.pageNotFoundDescription')}</p>
      <a href={resolve('/')} class="mt-4 inline-block text-sm font-medium text-blue-600 hover:underline">
        {i18n.t('common.ui.backToHome') || 'Back to Home'}
      </a>
    </div>
  {/if}
</div>